function activate(context) {
  var count = context.files.getAll().length;
  context.ui.addToolbarButton({
    icon: 'folder',
    label: context.t('toolbar.label', { count: count }),
    onClick: function () {
      context.ui.showModal(
        context.t('modal.title'),
        context.t('modal.body', { count: count })
      );
    },
  });
}
